from abc import ABC, abstractmethod

# Base class with special methods
class Animal(ABC):
    total_animals = 0  # class variable

    def __init__(self, name, species):
        self.name = name
        self.species = species
        Animal.total_animals += 1

    # Special method for string representation
    def __str__(self):
        return f"{self.name} ({self.species})"

    # Special method for unambiguous representation
    def __repr__(self):
        return f"Animal(name='{self.name}', species='{self.species}')"

    # Abstract method - must be implemented by subclasses
    @abstractmethod
    def make_sound(self):
        pass

    # Class method - operates on class variable
    @classmethod
    def get_total_animals(cls):
        return f"Total animals created: {cls.total_animals}"

    # Static method - utility function related to class
    @staticmethod
    def validate_name(name):
        return isinstance(name, str) and len(name) > 0

# Derived class 1
class Dog(Animal):
    def __init__(self, name, breed):
        super().__init__(name, "Canis familiaris")
        self.breed = breed

    def make_sound(self):
        return "Woof! Woof!"

# Derived class 2
class Cat(Animal):
    def __init__(self, name, color):
        super().__init__(name, "Felis catus")
        self.color = color

    def make_sound(self):
        return "Meow!"

# Demonstration
print("=== Creating Animals ===")
dog = Dog("Buddy", "Golden Retriever")
cat = Cat("Whiskers", "Orange")

print(f"Dog: {dog}")
print(f"Cat: {cat}")
print(repr(dog))

print("\n=== Polymorphism ===")
animals = [dog, cat]
for animal in animals:
    print(f"{animal.name} says: {animal.make_sound()}")

print("\n=== Class and Static Methods ===")
print(Animal.get_total_animals())
print(f"Valid name? {Animal.validate_name('Max')}")
print(f"Valid name? {Animal.validate_name('')}")
